const DEFAULT_KIMI_UPLOAD_ORIGIN="https://www.kimi.com",KIMI_UPLOAD_ENDPOINT_PATH="/api-claw/files:upload";export const resolveUploadEndpoint=i=>{const a=i.trim();if(!a)return"https://www.kimi.com/api-claw/files:upload";try{return`${new URL(a).origin}/api-claw/files:upload`}catch{const i=a.replace(/\/+$/,"").replace(/\/files:upload$/i,"").replace(/\/(apiv2|api-claw)(?:\/.*)?$/i,"");return i?`${i}/api-claw/files:upload`:"https://www.kimi.com/api-claw/files:upload"}};